+	cmd.Flags().StringVar(&maxAge, "max-age", "168h", "Remove checkpoints older than this duration (e.g., 24h, 7d)")
+	cmd.Flags().BoolVar(&all, "all", false, "Remove all checkpoints regardless of age")
